SELECT 
FROM attendance_record
WHERE user_id = #{userId}
  AND record_date >= #{startDate}
  AND record_date <= #{endDate}
ORDER BY record_date DESC

SELECT 
FROM attendance_record
WHERE 1 = 1
AND user_id = #{userId}
AND record_date = #{recordDate}
AND status = #{status}
ORDER BY record_date DESC, create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM attendance_record
WHERE 1 = 1
AND user_id = #{userId}
AND record_date = #{recordDate}
AND status = #{status}
